     1→import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
     2→import { Client } from '@opensearch-project/opensearch';
     3→
     4→import { EnvConfigService } from '@modules/env-config/env-config.service';
     5→
     6→import {
     7→	OPENSEARCH_HOST,
     8→	OPENSEARCH_PASSWORD,
     9→	OPENSEARCH_USERNAME,
    10→} from '@constants/env-variables.constant';
    11→
    12→import { LogExecution } from '@decorators/log-execution.decorator';
    13→
    14→@Injectable()
    15→export class OpensearchService implements OnModuleInit {
    16→	private readonly logger = new Logger(OpensearchService.name);
    17→	private client: Client;
    18→	private host: string;
    19→	private username: string;
    20→	private password: string;
    21→
    22→	constructor(private readonly configService: EnvConfigService) {}
    23→
    24→	onModuleInit(): void {
    25→		this.initializeOpensearchClient();
    26→	}
    27→
    28→	private initializeOpensearchClient(): void {
    29→		try {
    30→			this.host = this.configService.get<string>({ key: OPENSEARCH_HOST });
    31→			this.username = this.configService.get<string>({ key: OPENSEARCH_USERNAME });
    32→			this.password = this.configService.get<string>({ key: OPENSEARCH_PASSWORD });
    33→
    34→			this.client = new Client({
    35→				node: this.host,
    36→				auth: {
    37→					username: this.username,
    38→					password: this.password,
    39→				},
    40→			});
    41→
    42→			this.logger.log(`OpenSearch client initialized successfully. Host: ${this.host}`);
    43→		} catch (error: unknown) {
    44→			this.handleError({ context: 'Failed to initialize OpenSearch client', error });
    45→			throw error;
    46→		}
    47→	}
    48→
    49→	@LogExecution()
    50→	async healthCheck(): Promise<{ status: string; cluster_name: string }> {
    51→		try {
    52→			const response = await this.client.cluster.health();
    53→			return {
    54→				status: response.body.status,
    55→				cluster_name: response.body.cluster_name,
    56→			};
    57→		} catch (error: unknown) {
    58→			this.handleError({ context: 'OpenSearch health check failed', error });
    59→			throw error;
    60→		}
    61→	}
    62→
    63→	getClient(): Client {
    64→		return this.client;
    65→	}
    66→
    67→	@LogExecution()
    68→	async createIndex({
    69→		indexName,
    70→		mappings,
    71→		settings,
    72→	}: {
    73→		indexName: string;
    74→		mappings: Record<string, unknown>;
    75→		settings: Record<string, unknown>;
    76→	}): Promise<void> {
    77→		try {
    78→			const exists = await this.client.indices.exists({ index: indexName });
    79→
    80→			if (exists.body) {
    81→				this.logger.log(`Index ${indexName} already exists`);
    82→				return;
    83→			}
    84→
    85→			await this.client.indices.create({
    86→				index: indexName,
    87→				body: {
    88→					settings,
    89→					mappings,
    90→				},
    91→			});
    92→
    93→			this.logger.log(`Created OpenSearch index: ${indexName}`);
    94→		} catch (error: unknown) {
    95→			this.handleError({ context: `Failed to create index ${indexName}`, error });
    96→			throw error;
    97→		}
    98→	}
    99→
   100→	@LogExecution({ logParams: false, logResponse: false })
   101→	async bulkIndex({
   102→		indexName,
   103→		documents,
   104→	}: {
   105→		indexName: string;
   106→		documents: { _id: string; [key: string]: unknown }[];
   107→	}): Promise<{ indexed: number; errors: number }> {
   108→		try {
   109→			if (documents.length === 0) {
   110→				return { indexed: 0, errors: 0 };
   111→			}
   112→
   113→			const body = documents.flatMap((doc) => {
   114→				const { _id, ...docWithoutId } = doc;
   115→				return [{ index: { _index: indexName, _id } }, docWithoutId];
   116→			});
   117→
   118→			const response = await this.client.bulk({ body });
   119→
   120→			const errorItems = response.body.items.filter(
   121→				(item: { index?: { error?: unknown } }) => item.index?.error,
   122→			);
   123→
   124→			const errors = errorItems.length;
   125→			const indexed = documents.length - errors;
   126→
   127→			if (errors > 0) {
   128→				this.logger.warn(
   129→					`Bulk index completed with ${errors} errors out of ${documents.length} documents`,
   130→				);
   131→
   132→				const sampleErrors = errorItems
   133→					.slice(0, 3)
   134→					.map((item: { index?: { error?: { type?: string; reason?: string } } }) => ({
   135→						type: item.index?.error?.type,
   136→						reason: item.index?.error?.reason,
   137→					}));
   138→
   139→				this.logger.error(`Sample errors: ${JSON.stringify(sampleErrors, null, 2)}`);
   140→			}
   141→
   142→			return { indexed, errors };
   143→		} catch (error: unknown) {
   144→			this.handleError({ context: 'Bulk index failed', error });
   145→			throw error;
   146→		}
   147→	}
   148→
   149→	@LogExecution()
   150→	async deleteIndex({ indexName }: { indexName: string }): Promise<void> {
   151→		try {
   152→			const exists = await this.client.indices.exists({ index: indexName });
   153→
   154→			if (!exists.body) {
   155→				this.logger.log(`Index ${indexName} does not exist`);
   156→				return;
   157→			}
   158→
   159→			await this.client.indices.delete({ index: indexName });
   160→			this.logger.log(`Deleted OpenSearch index: ${indexName}`);
   161→		} catch (error: unknown) {
   162→			this.handleError({ context: `Failed to delete index ${indexName}`, error });
   163→			throw error;
   164→		}
   165→	}
   166→
   167→	private handleError({ context, error }: { context: string; error: unknown }): void {
   168→		const err = error instanceof Error ? error : new Error(String(error));
   169→		this.logger.error(`${context}: ${err.message}`, err.stack);
   170→	}
   171→}
