   103→	private normalizeCondensedFeatures({
   104→		condensedFeatures,
   105→	}: {
   106→		condensedFeatures: unknown;
   107→	}): string[] | null {
   108→		if (condensedFeatures === null || condensedFeatures === undefined) {
   109→			return null;
   110→		}
   111→
   112→		if (typeof condensedFeatures === 'string') {
   113→			return [condensedFeatures];
   114→		}
   115→
   116→		if (Array.isArray(condensedFeatures)) {
   117→			return condensedFeatures.map(String);
   118→		}
   119→
   120→		if (typeof condensedFeatures === 'object') {
   121→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
   122→				Array.isArray(value) ? value.map(String) : [String(value)],
   123→			);
   124→		}
   125→
   126→		return [JSON.stringify(condensedFeatures)];
   127→	}
