   135→			_id: style._id,
   136→			style_id: style.style_id,
   137→			product_id: style.product_id,
   138→			name: style.name ?? '',
   139→			features: style.features,
   140→			general_comments: style.general_comments,
   141→			decoration_method: style.decoration_method,
   142→			manufacturer: style.manufacturer,
   143→			primary_category_id: style.primary_category_id,
   144→			primary_category_name: style.primary_category_name,
   145→			product_type: style.product_type,
   146→			style_type: style.style_type,
   147→			broad_category_names: style.broad_category_names,
   148→			sub_category_names: style.sub_category_names,
   149→			minimum_quantity: style.minimum_quantity,
   150→			min_qty: style.min_qty,
   151→			default_quote_qty: style.default_quote_qty,
   152→			sizes: style.sizes,
   153→			turn_time: style.turn_time,
   154→			rush_turn_time: style.rush_turn_time,
   155→			no_minimum: style.no_minimum ? 1 : 0,
   156→			price_level: style.price_level,
   157→			rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
   158→			rating_count: style.rating_count,
   159→			default_unit_prices: style.default_unit_prices,
   160→			colors: style.colors,
   161→			style_card_image_url: style.style_card_image_url,
   162→			link: style.link,
   163→			brand: style.brand,
   164→			condensed_features: this.normalizeCondensedFeatures({
   165→				condensedFeatures: style.condensed_features,
