    14→import { data as correlationData } from '@seeds/category-correlations-09-2025';
    15→
    16→interface CorrelationData {
    17→	quote_mega_category: string;
    18→	quote_sub_category: string;
    19→	select_product_mega_category: string;
    20→	select_product_sub_category: string;
    21→	same_category_flag: boolean;
    22→	select_product_mega_cat: number;
    23→	quote_mega_cat: number;
    24→	percent: number;
    25→}
    26→
    27→@Command({
    28→	name: 'populate-category-correlations',
    29→	description: 'Populate categories_correlations table from CSV/JSON data',
    30→})
    31→export class PopulateCategoryCorrelationsCommand extends CommandRunner {
    32→	private readonly logger = new Logger(PopulateCategoryCorrelationsCommand.name);
    33→	private isShuttingDown = false;
    34→	private currentOperation: Promise<void> | null = null;
    35→
    36→	private readonly mmsBaseUrl = getEnv({ key: MMS_INTERNAL_BASE_URL });
    37→
    38→	constructor(private readonly categoryCorrelationsService: CategoryCorrelationsService) {
    39→		super();
    40→		this.setupGracefulShutdown();
    41→	}
    42→
    43→	@CronJobExecution({ jobName: 'populate-category-correlations' })
    44→	async run(): Promise<void> {
    45→		if (this.isShuttingDown) {
    46→			this.logger.warn('Command cancelled due to shutdown signal');
    47→			return;
    48→		}
    49→
    50→		try {
    51→			this.logger.log('Starting to populate category correlations data');
    52→
    53→			this.logger.log('Fetching categories from MMS...');
    54→			const categories = await this.fetchCategoriesFromMMS();
    55→			this.logger.log(`Fetched ${categories.length} categories from MMS`);
    56→
    57→			this.logger.log(`Loaded ${correlationData.length} correlation records`);
    58→
    59→			const processedCorrelations = this.processCorrelationData(
    60→				correlationData,
    61→				categories,
    62→			);
    63→
    64→			this.logger.log('Clearing existing category correlations...');
    65→			await this.categoryCorrelationsService.clearExistingData();
    66→
    67→			this.logger.log('Processing and populating category correlations...');
    68→			if (processedCorrelations.length > 0) {
    69→				await this.categoryCorrelationsService.bulkUpsert(processedCorrelations);
    70→				this.logger.log(
    71→					`Successfully populated ${processedCorrelations.length} category correlations`,
    72→				);
    73→			} else {
    74→				this.logger.warn(
    75→					'No correlations to populate - all records failed to match categories',
    76→				);
    77→			}
    78→
    79→			// eslint-disable-next-line
    80→			if (!this.isShuttingDown) {
    81→				this.logger.log('Successfully populated category correlations data');
    82→				return;
    83→			}
    84→		} catch (error) {
    85→			// eslint-disable-next-line
    86→			if (this.isShuttingDown) {
    87→				this.logger.warn('Command interrupted during shutdown');
    88→				return;
    89→			}
    90→			this.logger.error(
    91→				`Failed to populate category correlations: ${(error as Error).message}`,
    92→			);
    93→			process.exit(1);
    94→		} finally {
    95→			this.currentOperation = null;
    96→		}
    97→	}
