    99→	private processCorrelationData(
   100→		correlationData: CorrelationData[],
   101→		categories: MMSAllStyleCategory[],
   102→	): {
   103→		primaryCategoryId: number;
   104→		edgeId: number;
   105→		edgeWeight: number;
   106→	}[] {
   107→		const categoryNameToIdMap = new Map<string, number>();
   108→		categoryNameToIdMap.set('Soccer Jerseys'.toLowerCase(), 152);
   109→		categoryNameToIdMap.set('Signs, Banners, Decals'.toLowerCase(), 213);
   110→		categoryNameToIdMap.set('Lacrosse Jerseys'.toLowerCase(), 155);
   111→		categoryNameToIdMap.set('Quarter Zip Pullover Sweatshirts'.toLowerCase(), 163);
   112→		categoryNameToIdMap.set('Speakers & Audio'.toLowerCase(), 216);
   113→		categoryNameToIdMap.set('Screen Printed Polo Shirts'.toLowerCase(), 142);
   114→		categoryNameToIdMap.set('Phone Accessories'.toLowerCase(), 207);
   115→		categoryNameToIdMap.set('Baby T-shirts'.toLowerCase(), 165);
   116→		categoryNameToIdMap.set('Toddlers T-shirts'.toLowerCase(), 165);
   117→		categoryNameToIdMap.set('Computer Accessories'.toLowerCase(), 210);
   118→		categoryNameToIdMap.set('Baseball & Softball Jerseys'.toLowerCase(), 151);
   119→		categoryNameToIdMap.set('Basketball Jerseys'.toLowerCase(), 153);
   120→		categoryNameToIdMap.set('Pens'.toLowerCase(), 49);
   121→		categoryNameToIdMap.set('Chargers & Adapters'.toLowerCase(), 215);
   122→		categoryNameToIdMap.set('Sports & Fitness'.toLowerCase(), 200);
   123→
   124→		categories.forEach((category) => {
   125→			const categoryName = String(category['name']);
   126→			categoryNameToIdMap.set(categoryName.toLowerCase(), category._id);
   127→		});
   128→
   129→		const processedCorrelations: {
   130→			primaryCategoryId: number;
   131→			edgeId: number;
   132→			edgeWeight: number;
   133→		}[] = [];
   134→		let matchedRecords = 0;
   135→		const badCategories = new Set();
   136→
   137→		for (const record of correlationData) {
   138→			const quoteSubCategoryId = categoryNameToIdMap.get(
   139→				record.quote_sub_category.toLowerCase(),
   140→			);
   141→			const selectProductSubCategoryId = categoryNameToIdMap.get(
   142→				record.select_product_sub_category.toLowerCase(),
   143→			);
   144→
   145→			if (
   146→				quoteSubCategoryId &&
   147→				selectProductSubCategoryId &&
   148→				quoteSubCategoryId !== selectProductSubCategoryId
   149→			) {
   150→				processedCorrelations.push({
   151→					primaryCategoryId: quoteSubCategoryId,
   152→					edgeId: selectProductSubCategoryId,
   153→					edgeWeight: record.percent / 100,
   154→				});
   155→				matchedRecords++;
   156→			} else {
   157→				if (!quoteSubCategoryId) {
   158→					badCategories.add(record.quote_sub_category);
   159→				}
   160→				if (!selectProductSubCategoryId) {
   161→					badCategories.add(record.select_product_sub_category);
   162→				}
   163→				this.logger.debug(
   164→					`Could not find category IDs for: "${record.quote_sub_category}" (${quoteSubCategoryId}) -> "${record.select_product_sub_category} (${selectProductSubCategoryId})" or they are the same`,
   165→				);
   166→			}
   167→		}
   168→
   169→		this.logger.debug(
   170→			`Bad categories (${Array.from(badCategories).length}): ${JSON.stringify(Array.from(badCategories))}`,
   171→		);
   172→
   173→		this.logger.log(
   174→			`Processed ${matchedRecords} out of ${correlationData.length} correlation records (${((matchedRecords / correlationData.length) * 100).toFixed(1)}% match rate)`,
   175→		);
   176→
   177→		return processedCorrelations;
   178→	}
