   180→	private async fetchCategoriesFromMMS(): Promise<MMSAllStyleCategory[]> {
   181→		try {
   182→			const categoriesUrl = `${this.mmsBaseUrl}/mms/api/categories.json`;
   183→			this.logger.debug(`Fetching categories from: ${categoriesUrl}`);
   184→
   185→			const response = await fetch(categoriesUrl);
   186→
   187→			if (!response.ok) {
   188→				throw new Error(
   189→					`Failed to fetch categories from MMS: ${response.status} ${response.statusText}`,
   190→				);
   191→			}
   192→
   193→			const categories = (await response.json()) as MMSAllStyleCategory[];
   194→
   195→			if (!Array.isArray(categories)) {
   196→				throw new Error('Invalid response format: expected array of categories');
   197→			}
   198→
   199→			return categories;
   200→		} catch (error) {
   201→			this.logger.error(
   202→				`Error fetching categories from MMS: ${(error as Error).message}`,
   203→			);
   204→			throw error;
   205→		}
   206→	}
