#### 4.3 New private method: `buildCombinedTextForEmbedding()`

```typescript
private buildCombinedTextForEmbedding({
  style,
}: {
  style: IStylesMvBase;
}): string {
  const parts: string[] = [];

  if (style.name) parts.push(style.name);
  if (style.product_type) parts.push(style.product_type);
  if (style.primary_category_name) parts.push(style.primary_category_name);
  if (style.sub_category_names?.length) parts.push(style.sub_category_names.join(', '));
  if (style.broad_category_names?.length) parts.push(style.broad_category_names.join(', '));
  if (style.features) parts.push(style.features);
  if (style.general_comments) parts.push(style.general_comments);
  if (style.decoration_method) parts.push(style.decoration_method);
  if (style.manufacturer) parts.push(style.manufacturer);
  if (style.brand?.length) parts.push(style.brand.join(', '));
  if (style.style_type) parts.push(style.style_type);

  const condensed = this.normalizeCondensedFeatures({
    condensedFeatures: style.condensed_features,
  });
  if (condensed?.length) parts.push(condensed.join(', '));

  return parts.join(' | ');
}
```

**Rationale:** Using `|` separator gives clear boundaries between fields. Null/empty fields are skipped. The ordering (name first, then type, categories, features) puts the most semantically important text first, which slightly benefits models that have limited context windows (distilroberta has a 512 token limit).

#### 4.4 New method: `neuralSearch()`

```typescript
@LogExecution({
  paramFormatter: (params: {
    indexName: string;
    queryText: string;
    k: number;
    filters?: Record<string, unknown>;
  }) => ({
    indexName: params.indexName,
    queryText: params.queryText,
    k: params.k,
  }),
  responseFormatter: (response: IOpensearchNeuralSearchResponse) => ({
    total: response.total,
    hitsCount: response.hits.length,
  }),
})
async neuralSearch({
  indexName,
  queryText,
  k = 20,
  filters,
}: {
  indexName: string;
  queryText: string;
  k?: number;
  filters?: Record<string, unknown>;
}): Promise<IOpensearchNeuralSearchResponse> {
  const client = this.opensearchService.getClient();
  const modelId = this.configService.get<string>({ key: OPENSEARCH_MODEL_ID });

  const query: Record<string, unknown> = {
    neural: {
      product_embedding: {
        query_text: queryText,
        model_id: modelId,
        k,
      },
    },
  };

  const body: Record<string, unknown> = {
    size: k,
    query: filters
      ? { bool: { must: [query], filter: [filters] } }
      : query,
  };

  const response = await client.search({
    index: indexName,
    body,
  });

  return {
    hits: response.body.hits.hits.map(
      (hit: { _id: string; _score: number; _source: Record<string, unknown> }) => ({
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
      }),
    ),
    total:
      typeof response.body.hits.total === 'number'
        ? response.body.hits.total
        : response.body.hits.total.value,
    max_score: response.body.hits.max_score,
  };
}
```

**Dependencies needed:** This method requires `EnvConfigService` to read `OPENSEARCH_MODEL_ID`. The constructor currently only injects `OpensearchService`. We need to also inject `EnvConfigService`.

#### 4.5 New method: `hybridSearch()`

```typescript
@LogExecution({
  paramFormatter: (params: {
    indexName: string;
    queryText: string;
    keywordFields: string[];
    k: number;
  }) => ({
    indexName: params.indexName,
    queryText: params.queryText,
    k: params.k,
  }),
  responseFormatter: (response: IOpensearchNeuralSearchResponse) => ({
    total: response.total,
    hitsCount: response.hits.length,
  }),
})
async hybridSearch({
  indexName,
  queryText,
  keywordFields = ['name', 'features', 'general_comments'],
  k = 20,
  searchPipelineId = 'hybrid-search-pipeline',
  filters,
}: {
  indexName: string;
  queryText: string;
  keywordFields?: string[];
  k?: number;
  searchPipelineId?: string;
  filters?: Record<string, unknown>;
}): Promise<IOpensearchNeuralSearchResponse> {
  const client = this.opensearchService.getClient();
  const modelId = this.configService.get<string>({ key: OPENSEARCH_MODEL_ID });

  const keywordQuery = {
    multi_match: {
      query: queryText,
      fields: keywordFields,
    },
  };

  const neuralQuery = {
    neural: {
      product_embedding: {
        query_text: queryText,
        model_id: modelId,
        k,
      },
    },
  };

  const hybridQuery: Record<string, unknown> = {
    hybrid: {
      queries: [keywordQuery, neuralQuery],
    },
  };

  const body: Record<string, unknown> = {
    size: k,
    query: filters
      ? { bool: { must: [hybridQuery], filter: [filters] } }
      : hybridQuery,
  };

  const response = await client.search({
    index: indexName,
    body,
    search_pipeline: searchPipelineId,
  });

  // ... same result mapping as neuralSearch
}
```

**Note on `search_pipeline` parameter:** The `client.search()` method accepts query parameters. The `search_pipeline` parameter is passed as a query string parameter. In the `@opensearch-project/opensearch` client v3, this can be passed via `params` or directly as a top-level property. We should verify if `search_pipeline` is a recognized parameter in the client types; if not, we may need to use `querystring: { search_pipeline: pipelineId }` or cast.

